const raw = $input.first().json;
let data = raw.body;
if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch (e) {
    throw new Error('Body is not valid JSON');
  }
}
if (!data || typeof data !== 'object' || Array.isArray(data)) {
  data = raw;
}
const chatId = data.telegram_chat_id;
if (chatId === undefined || chatId === null || String(chatId).trim() === '') {
  throw new Error('Missing telegram_chat_id');
}
const action = data.action || 'save_message';
let messageText;
if (action === 'verify_telegram') {
  messageText = 'IntelliDigest: Telegram link confirmed. Saved replies will be sent to this chat.';
} else {
  const parts = [];
  if (data.user_message && String(data.user_message).trim()) {
    parts.push('Question:\n' + String(data.user_message).trim());
  }
  parts.push('Assistant:\n' + String(data.assistant_message || '').trim());
  const meta = [data.channel, data.persona].filter(Boolean).join(' · ');
  if (meta) {
    parts.push(meta);
  }
  messageText = parts.join('\n\n');
}
return [{ json: { telegram_chat_id: String(chatId).trim(), messageText, action } }];
